class Vector2D {
  constructor(vec) {
    this.vec = vec;
    this.row = 0;
    this.col = 0;
  }
  next() {
    this.hasNext();
    return this.vec[this.row][this.col++];
  }
  hasNext() {
    while (this.row < this.vec.length && this.col === this.vec[this.row].length) {
      this.row++;
      this.col = 0;
    }
    return this.row < this.vec.length;
  }
}

